solution_code:
#include <cmath>
#include <iomanip>
#include <iostream>
#include <memory>
#include <string>
#include <vector>

class Shape
{
public:
    virtual ~Shape() = default;
    virtual double area() const = 0;
    virtual void print(std::ostream& out) const = 0;
};

std::ostream& operator<<(std::ostream& out, const Shape& s)
{
    s.print(out);
    return out;
}

class Circle : public Shape
{
    double m_radius{};

public:
    Circle(double radius) : m_radius{ radius } {}

    double area() const override
    {
        return 3.14159265358979323846 * m_radius * m_radius;
    }

    void print(std::ostream& out) const override
    {
        out << "Circle: r=" << m_radius << " area=" << area();
    }
};

class Rectangle : public Shape
{
    double m_width{};
    double m_height{};

public:
    Rectangle(double w, double h) : m_width{ w }, m_height{ h } {}

    double area() const override
    {
        return m_width * m_height;
    }

    void print(std::ostream& out) const override
    {
        out << "Rect: " << m_width << "x" << m_height << " area=" << area();
    }
};

int main()
{
    std::cout << std::fixed << std::setprecision(2);

    int n{};
    std::cin >> n;

    std::vector<std::unique_ptr<Shape>> shapes;

    for (int i{ 0 }; i < n; ++i)
    {
        std::string type{};
        std::cin >> type;

        if (type == "circle")
        {
            double r{};
            std::cin >> r;
            shapes.push_back(std::make_unique<Circle>(r));
        }
        else
        {
            double w{}, h{};
            std::cin >> w >> h;
            shapes.push_back(std::make_unique<Rectangle>(w, h));
        }
    }

    double total{ 0.0 };
    for (const auto& s : shapes)
    {
        std::cout << *s << '\n';
        total += s->area();
    }

    std::cout << "Total area: " << total << '\n';

    return 0;
}

